    /// <summary>
    /// Generates a PDF report from an HTML file using wkhtmltopdf.
    /// </summary>
    /// <param name="htmlInputFilePath">The full path to the input HTML file.</param>
    /// <param name="pdfOutputFilePath">The full path where the generated PDF will be saved.</param>
    /// <param name="pageSize">Optional. The page size (e.g., "A4", "Letter"). Defaults to "A4".</param>
    /// <param name="orientation">Optional. The page orientation ("Portrait" or "Landscape"). Defaults to "Portrait".</param>
    /// <returns>A Task representing the asynchronous operation. The task completes with true if successful, false otherwise.</returns>
    /// <exception cref="ArgumentNullException">Thrown if htmlInputFilePath or pdfOutputFilePath is null or empty.</exception>
    /// <exception cref="FileNotFoundException">Thrown if the htmlInputFilePath does not exist.</exception>
    public static async Task<bool> GeneratePdfFromHtmlAsync(
        string htmlInputFilePath,
        string pdfOutputFilePath,
        string pageSize = "A4",
        string orientation = "Portrait")
    {
        if (string.IsNullOrWhiteSpace(htmlInputFilePath))
        {
            throw new ArgumentNullException(nameof(htmlInputFilePath), "HTML input file path cannot be null or empty.");
        }
        if (string.IsNullOrWhiteSpace(pdfOutputFilePath))
        {
            throw new ArgumentNullException(nameof(pdfOutputFilePath), "PDF output file path cannot be null or empty.");
        }
        if (!File.Exists(htmlInputFilePath))
        {
            throw new FileNotFoundException($"HTML input file not found at: {htmlInputFilePath}", htmlInputFilePath);
        }

        // Ensure the output directory exists
        string outputDirectory = Path.GetDirectoryName(pdfOutputFilePath);
        if (!string.IsNullOrEmpty(outputDirectory) && !Directory.Exists(outputDirectory))
        {
            Directory.CreateDirectory(outputDirectory);
        }

        // Construct wkhtmltopdf command arguments
        StringBuilder argsBuilder = new StringBuilder();
        argsBuilder.AppendFormat("--page-size \"{0}\" ", pageSize);
        argsBuilder.AppendFormat("--orientation \"{0}\" ", orientation);
        argsBuilder.AppendFormat("\"{0}\" ", htmlInputFilePath); // Input HTML file
        argsBuilder.AppendFormat("\"{0}\"", pdfOutputFilePath); // Output PDF file

        string wkhtmltopdfPath = "wkhtmltopdf"; // Assumes wkhtmltopdf is in system PATH

        ProcessStartInfo startInfo = new ProcessStartInfo
        {
            FileName = wkhtmltopdfPath,
            Arguments = argsBuilder.ToString(),
            UseShellExecute = false,
            RedirectStandardOutput = true,
            RedirectStandardError = true,
            CreateNoWindow = true
        };

        try
        {
            using (Process process = new Process { StartInfo = startInfo })
            {
                process.Start();

                // Read output and error streams asynchronously to prevent deadlocks
                string output = await process.StandardOutput.ReadToEndAsync();
                string error = await process.StandardError.ReadToEndAsync();

                await Task.Run(() => process.WaitForExit()); // Wait for the process to exit

                if (process.ExitCode == 0)
                {
                    // Optionally log success and output
                    // Console.WriteLine($"PDF generated successfully: {pdfOutputFilePath}");
                    // Console.WriteLine($"wkhtmltopdf Output: {output}");
                    return true;
                }
                else
