                    Console.Error.WriteLine($"wkhtmltopdf Output: {output}");
                    Console.Error.WriteLine($"wkhtmltopdf Error: {error}");
                    return false;
                }
            }
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"An exception occurred while trying to run wkhtmltopdf: {ex.Message}");
            Console.Error.WriteLine($"Ensure wkhtmltopdf is installed and accessible in the system's PATH, or provide its full executable path.");
            return false;
        }
    }

